import {
    within
} from "@testing-library/dom";
export class ToolbarModel {
    constructor(element) {
        this.element = element;
        this.queries = within(element)
    }
    getPrevButton() {
        return this.queries.getByRole("button", {
            name: "Previous page"
        })
    }
    getNextButton() {
        return this.queries.getByRole("button", {
            name: "Next page"
        })
    }
}
